commands.template:
[domain_realm]
    .{domain} = {DOMAIN_UPPER}
    {domain} = {DOMAIN_UPPER}

[libdefaults]
    default_realm = {DOMAIN_UPPER}
    dns_lookup_realm = false
    dns_lookup_kdc = true
    ticket_lifetime = 24h
    forwardable = true

[realms]
    {DOMAIN_UPPER} = {
        kdc = {domain_controller}
        admin_server = {domain_controller}
        default_domain = {domain}
    }
